operations.query:
query {
    products(
      storeId: "B2B-store"
      currencyCode: "USD"
      cultureName: "en-US"
      first: 1
      filter: "category.subtree:fc596540864a41bf8ab78734ee7353a3"
      facet: "price.USD"
    ) {
      totalCount
      range_facets { name label facetType ranges { count from to fromStr toStr label isSelected } }
    }
  }
